class TaskQueue:
    def __init__(self):
        self.tasks = []
    def add_task(self, name):
        self.tasks.append(name)
    def pop_task(self):
        return self.tasks.pop(0) if self.tasks else None

def run_practice():
    tq = TaskQueue()
    tq.add_task('Task 1')
    tq.add_task('Task 2')
    assert tq.pop_task() == 'Task 1'
    assert len(tq.tasks) == 1
    print('[PASS] Task queue basic schedulers verified.')

if __name__ == '__main__':
    run_practice()
